#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define BLOCK_SIZE 16
#define BLOCK_SIZE_C BLOCK_SIZE
#define BLOCK_SIZE_R BLOCK_SIZE

#define STR_SIZE 256

#define MAX_PD (3.0e6f)

#define PRECISION 0.001f
#define SPEC_HEAT_SI 1.75e6f
#define K_SI 100.0f

#define FACTOR_CHIP 0.5f

#define EXPAND_RATE 2

#define MIN(a, b) ((a) <= (b) ? (a) : (b))

const float t_chip = 0.0005f;
const float chip_height = 0.016f;
const float chip_width = 0.016f;

const float amb_temp = 80.0f;

__kernel void hotspot(
    const int total_iterations,
    __global const float* power,
    __global const float* temp_in,
    __global float* temp_out,
    const int col,
    const int row,
    const int borderCols,
    const int borderRows,
    const float Cap,
    const float Rx,
    const float Ry,
    const float Rz,
    const float step)
{
    int global_col = get_global_id(0);
    int global_row = get_global_id(1);

    int local_col = get_local_id(0);
    int local_row = get_local_id(1);

    int group_col = get_group_id(0);
    int group_row = get_group_id(1);

    int local_size_col = get_local_size(0);
    int local_size_row = get_local_size(1);

    // Compute block start indices
    int smallBlockCol = BLOCK_SIZE - (borderCols * 2);
    int smallBlockRow = BLOCK_SIZE - (borderRows * 2);

    int blockCol = group_col;
    int blockRow = group_row;

    int r_start = blockRow * smallBlockRow;
    int c_start = blockCol * smallBlockCol;

    // Clamp block boundaries
    int r_end = r_start + BLOCK_SIZE;
    if (r_end > row) r_end = row;
    int c_end = c_start + BLOCK_SIZE;
    if (c_end > col) c_end = col;

    // We will iterate total_iterations times
    // Use two buffers to ping-pong
    // temp_in and temp_out are buffers for current iteration and next iteration

    // We will do the iterations in the host, so here just compute one iteration
    // But since kernel is called with total_iterations, we do all iterations here

    // To do multiple iterations in kernel, we need local memory to store intermediate results
    // But original code does iteration in host, so here we do one iteration per kernel call

    // So this kernel computes one iteration of the transient temperature

    // Check if global indices are within grid
    if (global_row >= row || global_col >= col)
        return;

    // Compute index
    int idx = global_row * col + global_col;

    // For boundary conditions, check if cell is on edge
    int is_border = 0;
    if (global_row < borderRows || global_row >= (row - borderRows) ||
        global_col < borderCols || global_col >= (col - borderCols))
        is_border = 1;

    float Cap_1 = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    float delta = 0.0f;

    if (is_border) {
        // Handle boundary conditions explicitly
        if (global_row == 0 && global_col == 0) {
            delta = Cap_1 * (power[0] +
                (temp_in[1] - temp_in[0]) * Rx_1 +
                (temp_in[col] - temp_in[0]) * Ry_1 +
                (amb_temp - temp_in[0]) * Rz_1);
        }
        else if (global_row == 0 && global_col == col - 1) {
            int c = global_col;
            delta = Cap_1 * (power[c] +
                (temp_in[c - 1] - temp_in[c]) * Rx_1 +
                (temp_in[c + col] - temp_in[c]) * Ry_1 +
                (amb_temp - temp_in[c]) * Rz_1);
        }
        else if (global_row == row - 1 && global_col == col - 1) {
            int r = global_row;
            int c = global_col;
            int idx_rc = r * col + c;
            delta = Cap_1 * (power[idx_rc] +
                (temp_in[idx_rc - 1] - temp_in[idx_rc]) * Rx_1 +
                (temp_in[(r - 1) * col + c] - temp_in[idx_rc]) * Ry_1 +
                (amb_temp - temp_in[idx_rc]) * Rz_1);
        }
        else if (global_row == row - 1 && global_col == 0) {
            int r = global_row;
            int idx_r0 = r * col;
            delta = Cap_1 * (power[idx_r0] +
                (temp_in[idx_r0 + 1] - temp_in[idx_r0]) * Rx_1 +
                (temp_in[(r - 1) * col] - temp_in[idx_r0]) * Ry_1 +
                (amb_temp - temp_in[idx_r0]) * Rz_1);
        }
        else if (global_row == 0) {
            int c = global_col;
            delta = Cap_1 * (power[c] +
                (temp_in[c + 1] + temp_in[c - 1] - 2.0f * temp_in[c]) * Rx_1 +
                (temp_in[col + c] - temp_in[c]) * Ry_1 +
                (amb_temp - temp_in[c]) * Rz_1);
        }
        else if (global_col == col - 1) {
            int r = global_row;
            int c = global_col;
            int idx_rc = r * col + c;
            delta = Cap_1 * (power[idx_rc] +
                (temp_in[(r + 1) * col + c] + temp_in[(r - 1) * col + c] - 2.0f * temp_in[idx_rc]) * Ry_1 +
                (temp_in[idx_rc - 1] - temp_in[idx_rc]) * Rx_1 +
                (amb_temp - temp_in[idx_rc]) * Rz_1);
        }
        else if (global_row == row - 1) {
            int r = global_row;
            int c = global_col;
            int idx_rc = r * col + c;
            delta = Cap_1 * (power[idx_rc] +
                (temp_in[idx_rc + 1] + temp_in[idx_rc - 1] - 2.0f * temp_in[idx_rc]) * Rx_1 +
                (temp_in[(r - 1) * col + c] - temp_in[idx_rc]) * Ry_1 +
                (amb_temp - temp_in[idx_rc]) * Rz_1);
        }
        else if (global_col == 0) {
            int r = global_row;
            int idx_r0 = r * col;
            delta = Cap_1 * (power[idx_r0] +
                (temp_in[(r + 1) * col] + temp_in[(r - 1) * col] - 2.0f * temp_in[idx_r0]) * Ry_1 +
                (temp_in[idx_r0 + 1] - temp_in[idx_r0]) * Rx_1 +
                (amb_temp - temp_in[idx_r0]) * Rz_1);
        }
        else {
            // Should not reach here
            delta = 0.0f;
        }
    }
    else {
        // Interior points
        int r = global_row;
        int c = global_col;
        int idx_rc = r * col + c;
        delta = Cap_1 * (power[idx_rc] +
            (temp_in[(r + 1) * col + c] + temp_in[(r - 1) * col + c] - 2.0f * temp_in[idx_rc]) * Ry_1 +
            (temp_in[r * col + c + 1] + temp_in[r * col + c - 1] - 2.0f * temp_in[idx_rc]) * Rx_1 +
            (amb_temp - temp_in[idx_rc]) * Rz_1);
    }

    temp_out[idx] = temp_in[idx] + delta;
}
